# application/commands/base.py from abc import ABC, abstractmethod from dataclasses import dataclass from typing import TypeVar, Generic
T = TypeVar('T')
@dataclass class Command(ABC): """Base class for all commands.""" pass
class CommandHandler(ABC, Generic[T]): """Base class for command handlers."""
@abstractmethod async def handle(self, command: T) -> None: pass

# application/queries/base.py from abc import ABC, abstractmethod from dataclasses import dataclass from typing import TypeVar, Generic
T = TypeVar('T') R = TypeVar('R')
@dataclass class Query(ABC): """Base class for all queries.""" pass
class QueryHandler(ABC, Generic[T, R]): """Base class for query handlers."""
@abstractmethod async def handle(self, query: T) -> R: pass

# application/queries/orders/get_order.py from dataclasses import dataclass from typing import Optional from uuid import UUID
@dataclass class GetOrderQuery(Query): """Query to get order details.""" order_id: UUID
@dataclass class OrderDto: """Read model for order details.""" id: UUID customer_id: UUID status: str items: list total: float shipping_address: dict placed_at: Optional[str] created_at: str
class GetOrderHandler(QueryHandler[GetOrderQuery, OrderDto]): """Handler for GetOrderQuery."""
def __init__(self, read_store: ReadStore): self._read_store = read_store
async def handle(self, query: GetOrderQuery) -> OrderDto: # Read from optimized read store data = await self._read_store.get(f"order:{query.order_id}")
if not data: raise OrderNotFoundError(query.order_id)
return OrderDto(**data)
@dataclass class ListOrdersQuery(Query): """Query to list orders for a customer.""" customer_id: UUID status: Optional[str] = None page: int = 1 page_size: int = 20
@dataclass class OrderListDto: """Paginated list of orders.""" items: list[OrderSummaryDto] total: int page: int page_size: int
class ListOrdersHandler(QueryHandler[ListOrdersQuery, OrderListDto]): """Handler for ListOrdersQuery."""
def __init__(self, read_store: ReadStore): self._read_store = read_store
async def handle(self, query: ListOrdersQuery) -> OrderListDto: # Query optimized read model orders = await self._read_store.query( index="orders_by_customer", customer_id=str(query.customer_id), status=query.status, offset=(query.page - 1) * query.page_size, limit=query.page_size, )
total = await self._read_store.count( index="orders_by_customer", customer_id=str(query.customer_id), status=query.status, )
return OrderListDto( items=[OrderSummaryDto(**o) for o in orders], total=total, page=query.page, page_size=query.page_size, )

# infrastructure/bus/mediator.py
from typing import Dict, Type, TypeVar, Generic
from dataclasses import dataclass

T = TypeVar('T')


class Mediator:
    """Mediator for dispatching commands and queries."""

    def __init__(self):
        self._command_handlers: Dict[Type, CommandHandler] = {}
        self._query_handlers: Dict[Type, QueryHandler] = {}

    def register_command_handler(
        self,
        command_type: Type[Command],
        handler: CommandHandler,
    ) -> None:
        self._command_handlers[command_type] = handler

    def register_query_handler(
        self,
        query_type: Type[Query],
        handler: QueryHandler,
    ) -> None:
        self._query_handlers[query_type] = handler

    async def send(self, command: Command) -> None:
        """Dispatch command to handler."""
        handler = self._command_handlers.get(type(command))
        if not handler:
            raise HandlerNotFoundError(f"No handler for {type(command)}")
        await handler.handle(command)

    async def query(self, query: Query) -> T:
        """Dispatch query to handler."""
        handler = self._query_handlers.get(type(query))
        if not handler:
            raise HandlerNotFoundError(f"No handler for {type(query)}")
        return await handler.handle(query)

# API usage @router.post("/orders") async def place_order( request: PlaceOrderRequest, mediator: Mediator = Depends(get_mediator), ): command = PlaceOrderCommand( order_id=uuid4(), customer_id=request.customer_id, items=request.items, shipping_address=request.shipping_address, )
await mediator.send(command)
return {"order_id": str(command.order_id)}
@router.get("/orders/{order_id}") async def get_order( order_id: UUID, mediator: Mediator = Depends(get_mediator), ): query = GetOrderQuery(order_id=order_id) order = await mediator.query(query) return order
